#include <iostream>
#include <string>
#include <vector>
#include <stdexcept>

// --- noexcept functions ---

// Function that guarantees not to throw
void safeFunction() noexcept {
    std::cout << "This function never throws!" << std::endl;
}

// Function that might throw (not noexcept)
void riskyFunction() {
    throw std::runtime_error("Something went wrong!");
}

// Move constructor with noexcept
class GameResource {
private:
    std::string name;
    int* data;
    int size;

public:
    GameResource(std::string n, int s) : name(n), size(s) {
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = i;
        }
        std::cout << "Resource '" << name << "' created" << std::endl;
    }

    ~GameResource() {
        delete[] data;
        std::cout << "Resource '" << name << "' destroyed" << std::endl;
    }

    // Move constructor — noexcept is important!
    GameResource(GameResource&& other) noexcept 
        : name(std::move(other.name)), data(other.data), size(other.size) {
        other.data = nullptr;
        other.size = 0;
        std::cout << "Resource moved (noexcept)" << std::endl;
    }

    void display() const {
        std::cout << name << " (size: " << size << ")" << std::endl;
    }
};

// --- Exception safety levels ---

class SafeContainer {
private:
    std::vector<int> data;
    int extraData;

public:
    // Strong exception guarantee
    void addWithStrongGuarantee(const std::vector<int>& newData) {
        std::vector<int> temp = data;  // Copy
        temp.insert(temp.end(), newData.begin(), newData.end());
        data.swap(temp);  // No-throw swap
        // If anything threw, data is unchanged
    }

    // Basic exception guarantee
    void addWithBasicGuarantee(const std::vector<int>& newData) {
        // May leave object in valid but modified state
        data.insert(data.end(), newData.begin(), newData.end());
    }

    void display() const {
        std::cout << "Container: ";
        for (int n : data) std::cout << n << " ";
        std::cout << std::endl;
    }
};

// --- noexcept specifier ---

void testNoexcept() noexcept {
    std::cout << "This function is marked noexcept" << std::endl;
    // If it throws, program terminates
}

// --- noexcept operator ---

void checkNoexcept() {
    std::cout << "\n--- noexcept operator ---" << std::endl;
    std::cout << "safeFunction: " << noexcept(safeFunction()) << std::endl;
    std::cout << "riskyFunction: " << noexcept(riskyFunction()) << std::endl;
    std::cout << "testNoexcept: " << noexcept(testNoexcept()) << std::endl;
    std::cout << "std::vector::swap: " << noexcept(std::declval<std::vector<int>>().swap(std::declval<std::vector<int>>())) << std::endl;
}

int main() {
    std::cout << "=== noexcept & Exception Safety ===" << std::endl;

    // 1. noexcept functions
    std::cout << "\n--- noexcept functions ---" << std::endl;
    safeFunction();

    try {
        riskyFunction();
    } catch (const std::exception& e) {
        std::cout << "Caught: " << e.what() << std::endl;
    }

    // 2. Move with noexcept
    std::cout << "\n--- Move with noexcept ---" << std::endl;
    GameResource res1("Resource1", 5);
    GameResource res2 = std::move(res1);  // Move constructor (noexcept)
    res2.display();

    // 3. Exception safety levels
    std::cout << "\n--- Strong Exception Guarantee ---" << std::endl;
    SafeContainer container;
    container.display();

    try {
        container.addWithStrongGuarantee({10, 20, 30});
    } catch (...) {
        std::cout << "Exception caught!" << std::endl;
    }
    container.display();

    // 4. noexcept operator
    checkNoexcept();

    // 5. When to use noexcept
    std::cout << "\n--- When to use noexcept ---" << std::endl;
    std::cout << "✅ Move constructors/assignment" << std::endl;
    std::cout << "✅ Swap functions" << std::endl;
    std::cout << "✅ Functions that can't throw" << std::endl;
    std::cout << "❌ Functions that might throw" << std::endl;

    std::cout << "\n--- Exception Safety Levels ---" << std::endl;
    std::cout << "🔹 Basic: Object is valid but modified" << std::endl;
    std::cout << "🔹 Strong: Operation succeeds or object unchanged" << std::endl;
    std::cout << "🔹 No-throw: Guaranteed not to throw" << std::endl;

    return 0;
}

