#include <iostream>
#include <string>
#include <stdexcept>

int add(int a, int b) noexcept {
    return a + b;
}

void printMessage(const std::string& msg) noexcept {
    std::cout << msg << std::endl;
}

int divide(int a, int b) {
    if (b == 0) {
        throw std::runtime_error("Division by zero!");
    }
    return a / b;
}

class GameData {
private:
    int* data;
    int size;

public:
    GameData(int s) : size(s) {
        data = new int[size];
        for (int i = 0; i < size; i++) data[i] = i;
    }

    ~GameData() { delete[] data; }

    // noexcept move constructor
    GameData(GameData&& other) noexcept 
        : data(other.data), size(other.size) {
        other.data = nullptr;
        other.size = 0;
    }

    void display() const {
        std::cout << "GameData (size: " << size << ")" << std::endl;
    }
};

int main() {
    std::cout << "=== noexcept Demo ===" << std::endl;

    printMessage("Hello from noexcept function!");
    std::cout << "add(5,3) = " << add(5, 3) << std::endl;

    std::cout << "\n--- noexcept operator ---" << std::endl;
    std::cout << "add is noexcept: " << noexcept(add(5, 3)) << std::endl;
    std::cout << "divide is noexcept: " << noexcept(divide(10, 2)) << std::endl;
    std::cout << "printMessage is noexcept: " << noexcept(printMessage("test")) << std::endl;

    try {
        std::cout << "\n--- divide (with exception) ---" << std::endl;
        int result = divide(10, 0);
        std::cout << "Result: " << result << std::endl;
    } catch (const std::runtime_error& e) {
        std::cout << "Caught: " << e.what() << std::endl;
    }

    std::cout << "\n--- noexcept Move Constructor ---" << std::endl;
    GameData g1(10);
    g1.display();
    GameData g2 = std::move(g1);  // Uses noexcept move
    g2.display();

    return 0;
}
